template:
{{ define "callBotImage (Multi)" }}

    {{- $commonLabels := .CommonLabels -}}
    {{- if index $commonLabels "alertname" -}}
        {{- $commonLabels = $commonLabels.Remove (stringSlice "alertname") }}
    {{ end -}}
    {{- if index $commonLabels "grafana_folder" -}}
        {{- $commonLabels = $commonLabels.Remove (stringSlice "grafana_folder") }}
    {{ end -}}
    {{- if index $commonLabels "rulename" -}}
        {{- $commonLabels = $commonLabels.Remove (stringSlice "rulename") }}
    {{ end -}}
    {{- if index $commonLabels "instance " -}}
        {{- $commonLabels = $commonLabels.Remove (stringSlice "instance ") }}
    {{ end -}}
    {{ template "print" $commonLabels }}
    {{ range .Alerts -}}
        {{ template "ListUpLabels" . }}
    {{ end -}}
{{- end -}}


{{- define "ListUpLabels" -}}
    {{- $target := "ServerName" -}}
    {{- $labels := .Labels -}}
    {{- with index $labels $target -}}
        {{- with $target }}{{ index $labels $target }}{{ end -}}
    {{- end -}}
{{- end -}}

{{- define "print" -}}
    {{ range .SortedPairs }}
        {{- .Name }} = {{ .Value }}{{ " " }}
    {{- end -}}
{{- end -}}
